void roundRobin(Process readyQueue[], int quantum) {
  int time = 0;

  while (!isEmpty(readyQueue)) {
    Process current = dequeue(readyQueue);
    int slice = current.remaining < quantum
      ? current.remaining : quantum;

    runOnCpu(current, slice);
    current.remaining -= slice;
    time += slice;

    if (current.remaining == 0) {
      markComplete(current);
    } else {
      enqueue(readyQueue, current);
    }
  }
}
